import{_ as o,o as a,c as r,a3 as t}from"./chunks/framework.BlfGB29P.js";const p=JSON.parse('{"title":"三十一、双碳业务 × Java 复合题","description":"","frontmatter":{"title":"三十一、双碳业务 × Java 复合题"},"headers":[],"relativePath":"31-carbon-java-composite.md","filePath":"31-carbon-java-composite.md","lastUpdated":null}'),n={name:"31-carbon-java-composite.md"};function d(s,e,c,i,l,h){return a(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="三十一、双碳业务-×-java-复合题" tabindex="-1">三十一、双碳业务 × Java 复合题 <a class="header-anchor" href="#三十一、双碳业务-×-java-复合题" aria-label="Permalink to &quot;三十一、双碳业务 × Java 复合题&quot;">​</a></h1><h3 id="q-31-1" tabindex="-1">1. 用 JDK21 虚拟线程对百万级碳足迹做批量 Embedding 向量化，如何避免 synchronized 钉住（pinning）陷阱并限流？ <a class="header-anchor" href="#q-31-1" aria-label="Permalink to &quot;1. 用 JDK21 虚拟线程对百万级碳足迹做批量 Embedding 向量化，如何避免 synchronized 钉住（pinning）陷阱并限流？ {#q-31-1}&quot;">​</a></h3><p><strong>难度</strong>：★★★</p><p><strong>考点</strong>：Virtual Threads 调度机制、synchronized 钉住平台线程、I/O 密集型并发限流、Semaphore 连接池控制。</p><p><strong>参考答案</strong>：百万级碳足迹文本调用 Embedding API 属 I/O 密集，适合 <code>Executors.newVirtualThreadPerTaskExecutor()</code>。关键是避免 synchronized 代码块/方法钉住载体线程（carrier thread），否则虚拟线程退化为平台线程，失去高并发优势；应改用 <code>ReentrantLock</code>。调用外部 Embedding 服务需限流，用 <code>Semaphore</code> 控制并发连接数（如 200），超出则虚拟线程 <code>acquire()</code> 阻塞让出底层载体，不影响吞吐。</p><p><strong>深度解析</strong>：JDK21 中 <code>synchronized</code> 在虚拟线程持锁且发生阻塞 I/O 时会钉住 carrier thread（JEP 444 已知限制，JDK24 才支持虚拟线程内 synchronized 不钉住）。钉住会降低并行度，监控可用 <code>-Djdk.tracePinnedThreads=full</code>。连接池限流本质是对稀缺资源（HTTP 连接）做准入控制，Virtual Threads 本身不解决下游限流，必须配合 <code>Semaphore</code> 或 <code>HttpClient</code> 的 <code>Executor</code> 限制。</p><p><strong>易错点</strong>：以为开了虚拟线程就无需限流；在虚拟线程里用 synchronized 包裹含 I/O 的临界区导致 pinning；Semaphore 忘记 <code>release()</code> 造成永久饥饿。</p><h4 id="f-31-1" tabindex="-1">追问： <a class="header-anchor" href="#f-31-1" aria-label="Permalink to &quot;追问： {#f-31-1}&quot;">​</a></h4><h5 id="fu-31-1" tabindex="-1">追问1：如何验证是否发生了 synchronized pinning？ <a class="header-anchor" href="#fu-31-1" aria-label="Permalink to &quot;追问1：如何验证是否发生了 synchronized pinning？ {#fu-31-1}&quot;">​</a></h5><p><strong>答</strong>：启动时加 <code>-Djdk.tracePinnedThreads=full</code>，一旦虚拟线程在 synchronized 内阻塞，JVM 打印堆栈定位钉住点；生产可用 JFR 事件 <code>jdk.VirtualThreadPinned</code> 量化频率，再针对性改造为 <code>ReentrantLock</code>。</p><h5 id="fu-31-2" tabindex="-1">追问2：Semaphore 限流和虚拟线程数量如何配合？ <a class="header-anchor" href="#fu-31-2" aria-label="Permalink to &quot;追问2：Semaphore 限流和虚拟线程数量如何配合？ {#fu-31-2}&quot;">​</a></h5><p><strong>答</strong>：虚拟线程近乎无限，但下游 Embedding 有 QPS 上限；令 <code>Semaphore permits = 下游安全并发数</code>，所有任务先 <code>acquire()</code> 再发请求，确保任一时刻外部调用不超阈值，多出的虚拟线程在信号量处挂起而非压垮下游。</p><h3 id="q-31-2" tabindex="-1">2. 碳因子检索中 MySQL 全文、Elasticsearch、Milvus 三者职责如何划分？ <a class="header-anchor" href="#q-31-2" aria-label="Permalink to &quot;2. 碳因子检索中 MySQL 全文、Elasticsearch、Milvus 三者职责如何划分？ {#q-31-2}&quot;">​</a></h3><p><strong>难度</strong>：★★</p><p><strong>考点</strong>：检索场景选型、向量检索与文本检索边界、职责单一化、碳因子元数据与语义检索协同。</p><p><strong>参考答案</strong>：MySQL 全文负责结构化精确匹配（如按因子编码、行业分类精确查询）；ES 负责海量碳因子文本的多维过滤与关键词检索（分页、聚合统计）；Milvus 负责语义相似因子召回（LCA 过程名称向量近邻搜索）。三者按「精确 / 关键词 / 语义」分层，避免用 MySQL 扛模糊语义、用 Milvus 扛精确过滤。</p><p><strong>深度解析</strong>：碳因子数据有强结构化属性（来源、年份、地区），精确查询走 MySQL 保证事务一致；ES 的倒排索引适合 <code>match</code> 模糊与复合过滤；Milvus 的 ANN（HNSW/IVF）适合「相似排放过程」推荐。混合检索可在应用层融合：先 ES 过滤候选集，再 Milvus 按向量重排，降低向量库压力。</p><p><strong>易错点</strong>：把全部检索压到 Milvus，缺失结构化过滤能力；用 MySQL <code>LIKE</code> 做全文，性能随数据量骤降；忽视三库数据一致性导致「查得到但算出来是旧因子」。</p><h4 id="f-31-2" tabindex="-1">追问： <a class="header-anchor" href="#f-31-2" aria-label="Permalink to &quot;追问： {#f-31-2}&quot;">​</a></h4><h5 id="fu-31-3" tabindex="-1">追问1：三库数据一致性如何保障？ <a class="header-anchor" href="#fu-31-3" aria-label="Permalink to &quot;追问1：三库数据一致性如何保障？ {#fu-31-3}&quot;">​</a></h5><p><strong>答</strong>：以 MySQL 为源，通过 CDC（如 Debezium/Flink CDC）捕获变更，异步同步到 ES 与 Milvus，保证最终一致；并对账任务定时校验向量库与关系库因子版本号，发现漂移即重推。</p><h5 id="fu-31-4" tabindex="-1">追问2：为什么不让 Milvus 直接做精确过滤？ <a class="header-anchor" href="#fu-31-4" aria-label="Permalink to &quot;追问2：为什么不让 Milvus 直接做精确过滤？ {#fu-31-4}&quot;">​</a></h5><p><strong>答</strong>：Milvus 的标量过滤能力弱于 ES，且其 ANN 返回的是近似 TopK，无法做 <code>group by</code>、范围聚合等关系运算；强行使用会降低召回精度并增加资源开销。</p><h3 id="q-31-3" tabindex="-1">3. 用 Seata AT 模式保证「碳报告生成 + 配额扣减」跨服务一致，原理与局限？ <a class="header-anchor" href="#q-31-3" aria-label="Permalink to &quot;3. 用 Seata AT 模式保证「碳报告生成 + 配额扣减」跨服务一致，原理与局限？ {#q-31-3}&quot;">​</a></h3><p><strong>难度</strong>：★★★</p><p><strong>考点</strong>：Seata AT 两阶段、undo_log 回滚、全局锁、跨微服务事务边界、碳配额一致性。</p><p><strong>参考答案</strong>：在「生成碳报告」与「扣减 AI 配额」两个微服务间加 <code>@GlobalTransactional</code>。Seata AT 一阶段执行业务 SQL 同时记录 <code>undo_log</code> 与 <code>before/after</code> 镜像，并加全局锁；二阶段 TC 通知提交则异步清 undo_log，通知回滚则按镜像反向补偿。这样报告生成失败时配额自动回补，避免「扣了配额却没报告」。</p><p><strong>深度解析</strong>：AT 基于数据源代理（<code>DataSourceProxy</code>）解析 SQL 生成回滚日志，对业务侵入低。但全局锁在高并发扣减场景可能成为热点，且要求各库有 <code>undo_log</code> 表、网络分区时可能悬挂。相比 TCC，AT 无需手写补偿，但牺牲了「预留资源」的强隔离。参考 Seata 1.x 官方文档 AT 模式。</p><p><strong>易错点</strong>：在 AT 事务内混用本地事务与 RPC 导致 undo_log 与业务不一致；热点配额行加全局锁引发长事务阻塞；忘记建 <code>undo_log</code> 表。</p><h4 id="f-31-3" tabindex="-1">追问： <a class="header-anchor" href="#f-31-3" aria-label="Permalink to &quot;追问： {#f-31-3}&quot;">​</a></h4><h5 id="fu-31-5" tabindex="-1">追问1：AT 与 TCC 在这个场景怎么选？ <a class="header-anchor" href="#fu-31-5" aria-label="Permalink to &quot;追问1：AT 与 TCC 在这个场景怎么选？ {#fu-31-5}&quot;">​</a></h5><p><strong>答</strong>：若配额扣减需要「先冻结再确认」的强隔离（防超发），TCC 更合适；若追求低侵入、可容忍最终一致，AT 足够。报告生成属长任务，常配合 TCC 的 Try 预留配额。</p><h5 id="fu-31-6" tabindex="-1">追问2：AT 模式回滚失败怎么办？ <a class="header-anchor" href="#fu-31-6" aria-label="Permalink to &quot;追问2：AT 模式回滚失败怎么办？ {#fu-31-6}&quot;">​</a></h5><p><strong>答</strong>：TC 会重试回滚；<code>undo_log</code> 含 <code>xid</code> 与 <code>branchId</code>，幂等重试安全。极端脏写需人工介入，因此生产应配监控告警与定期 <code>undo_log</code> 清理。</p><h3 id="q-31-4" tabindex="-1">4. 用 TCC 三阶段实现碳配额扣减，如何处理空回滚、防悬挂、幂等？ <a class="header-anchor" href="#q-31-4" aria-label="Permalink to &quot;4. 用 TCC 三阶段实现碳配额扣减，如何处理空回滚、防悬挂、幂等？ {#q-31-4}&quot;">​</a></h3><p><strong>难度</strong>：★★★</p><p><strong>考点</strong>：TCC Try-Confirm-Cancel、空回滚、防悬挂、幂等控制、配额冻结语义。</p><p><strong>参考答案</strong>：Try 阶段冻结配额（金额置冻结字段而非直接扣减）；Confirm 真正扣减并清冻结；Cancel 释放冻结。空回滚：Cancel 先于 Try 到达（Try 网络失败），需识别「无 Try 记录」跳过补偿。防悬挂：Try 在网络恢复后迟到到达，需记已回滚标记拒绝执行。幂等：每阶段以 <code>branchId</code>/<code>actionId</code> 落库标记，重复调用直接返回。</p><p><strong>深度解析</strong>：TCC 核心难点在异常顺序。标准做法是维护「事务动作记录表」：Try 写入 <code>status=TRYING</code>；Cancel 若查无记录则写 <code>status=CANCELLED</code> 并空回滚；若发现 <code>status=CANCELLED</code> 再收到 Try 则直接拒绝（防悬挂）。Confirm/Cancel 均以 <code>actionId</code> 唯一约束保证幂等。参考《Seata TCC 防悬挂设计》与 Alibaba TCC 规范。</p><p><strong>易错点</strong>：Cancel 不空回滚导致误释放；Try 迟到造成配额被冻结却不解除（悬挂）；Confirm 未幂等致重复扣减。</p><h4 id="f-31-4" tabindex="-1">追问： <a class="header-anchor" href="#f-31-4" aria-label="Permalink to &quot;追问： {#f-31-4}&quot;">​</a></h4><h5 id="fu-31-7" tabindex="-1">追问1：为什么不直接在 Try 里扣减而要先冻结？ <a class="header-anchor" href="#fu-31-7" aria-label="Permalink to &quot;追问1：为什么不直接在 Try 里扣减而要先冻结？ {#fu-31-7}&quot;">​</a></h5><p><strong>答</strong>：直接扣减则 Confirm 时无法区分「已扣」与「未扣」，Cancel 也难回补；冻结把「预留」与「提交」分离，使 Confirm/Cancel 语义清晰且可幂等重入。</p><h5 id="fu-31-8" tabindex="-1">追问2：actionId 如何生成保证全局唯一？ <a class="header-anchor" href="#fu-31-8" aria-label="Permalink to &quot;追问2：actionId 如何生成保证全局唯一？ {#fu-31-8}&quot;">​</a></h5><p><strong>答</strong>：由 <code>xid + branchId + actionName</code> 组合，或业务侧用 <code>userId + quotaType + 全局事务号</code> 拼成唯一键，配合数据库唯一索引实现天然幂等。</p><h3 id="q-31-5" tabindex="-1">5. 用 Redis + Lua 做碳配额原子扣减防超发，脚本怎么写？ <a class="header-anchor" href="#q-31-5" aria-label="Permalink to &quot;5. 用 Redis + Lua 做碳配额原子扣减防超发，脚本怎么写？ {#q-31-5}&quot;">​</a></h3><p><strong>难度</strong>：★★★</p><p><strong>考点</strong>：Redis Lua 原子性、EVAL 脚本、分布式扣减、防超发、返回值设计。</p><p><strong>参考答案</strong>：用一段 Lua 脚本在 Redis 单线程内完成「读取余额→判断≥扣减量→扣减/返回失败」，保证原子。脚本先 <code>GET quota:{tenant}:{userId}</code>，若 <code>tonumber(balance) &gt;= cost</code> 则 <code>DECRBY</code> 并返回 1，否则返回 0。客户端据返回值决定放行或拒绝，杜绝 <code>GET</code> 与 <code>DECR</code> 间的竞态超发。</p><p><strong>深度解析</strong>：Redis 执行 Lua 期间阻塞其他命令，因此「判断+扣减」不可拆分，比「先 GET 再 DECRBY」安全。需设 Key 过期或初始化防止冷启动无值；扣减失败不落库，由业务层走配额不足流程。注意 Lua 内不可用非确定性命令（如 <code>TIME</code> 部分场景），且脚本不宜过长以免阻塞。</p><p><strong>易错点</strong>：用 <code>INCRBY</code> 配合应用层判断导致「读后写」竞态超发；Lua 返回字符串与数字混用致客户端解析错误；未处理 Key 不存在导致首次必失败。</p><h4 id="f-31-5" tabindex="-1">追问： <a class="header-anchor" href="#f-31-5" aria-label="Permalink to &quot;追问： {#f-31-5}&quot;">​</a></h4><h5 id="fu-31-9" tabindex="-1">追问1：扣减后如何与 MySQL 配额对账？ <a class="header-anchor" href="#fu-31-9" aria-label="Permalink to &quot;追问1：扣减后如何与 MySQL 配额对账？ {#fu-31-9}&quot;">​</a></h5><p><strong>答</strong>：Redis 作高速扣减层，MySQL 作权威账本；异步将扣减事件发 MQ，消费者更新 MySQL 余额，定时任务比对 Redis 与 MySQL 差异，差异超阈值告警并补偿。</p><h5 id="fu-31-10" tabindex="-1">追问2：多 Redis 分片下 Lua 还能原子吗？ <a class="header-anchor" href="#fu-31-10" aria-label="Permalink to &quot;追问2：多 Redis 分片下 Lua 还能原子吗？ {#fu-31-10}&quot;">​</a></h5><p><strong>答</strong>：Lua 仅单实例/单 slot 原子；若配额 Key 被 hash 到不同 slot，需用 Hash Tag（如 <code>{tenant}</code> 包裹）保证同槽，或改用 Redis Cluster 的 transaction 局限方案，否则需上层加分布式锁。</p><h3 id="q-31-6" tabindex="-1">6. 单机 AtomicInteger/LongAdder 方案与 Redis 分布式多实例方案如何取舍？ <a class="header-anchor" href="#q-31-6" aria-label="Permalink to &quot;6. 单机 AtomicInteger/LongAdder 方案与 Redis 分布式多实例方案如何取舍？ {#q-31-6}&quot;">​</a></h3><p><strong>难度</strong>：★★</p><p><strong>考点</strong>：单机并发计数 vs 分布式原子、LongAdder 高并发优化、分布式一致性、碳配额部署形态。</p><p><strong>参考答案</strong>：若碳配额服务是单实例部署，用 <code>AtomicInteger</code>（低竞争）或 <code>LongAdder</code>（高并发写，减少 CAS 争用）即可保证原子扣减。但配额服务通常多实例横向扩展，JVM 内计数不共享，必须用 Redis/数据库等集中存储。LongAdder 通过分片 Cell 降低热点，但多线程读取 <code>sum()</code> 非瞬时一致，不适合「精确余额」场景。</p><p><strong>深度解析</strong>：<code>AtomicInteger</code> 高并发下 CAS 自旋开销大；<code>LongAdder</code> 把计数分散到多个 Cell，写快但 <code>sum()</code> 是快照和。二者皆仅限单 JVM。分布式下 Redis Lua 或数据库 <code>UPDATE ... SET balance=balance-cost WHERE balance&gt;=cost</code> 行锁才是正确方案。参考 JUC 源码 <code>Striped64</code>。</p><p><strong>易错点</strong>：多实例仍用 <code>AtomicInteger</code> 导致各实例独立计数、总配额被放大超发；用 <code>LongAdder</code> 做余额判断致读到过期值。</p><h4 id="f-31-6" tabindex="-1">追问： <a class="header-anchor" href="#f-31-6" aria-label="Permalink to &quot;追问： {#f-31-6}&quot;">​</a></h4><h5 id="fu-31-11" tabindex="-1">追问1：数据库行锁扣减和 Redis 比优缺点？ <a class="header-anchor" href="#fu-31-11" aria-label="Permalink to &quot;追问1：数据库行锁扣减和 Redis 比优缺点？ {#fu-31-11}&quot;">​</a></h5><p><strong>答</strong>：数据库 <code>WHERE balance&gt;=cost</code> 强一致、无需对账，但 TPS 受限于单行锁与连接；Redis 吞吐高但需对账补账。配额量小且要求强一致可选 DB，高并发选 Redis+对账。</p><h5 id="fu-31-12" tabindex="-1">追问2：LongAdder 适合什么碳业务统计？ <a class="header-anchor" href="#fu-31-12" aria-label="Permalink to &quot;追问2：LongAdder 适合什么碳业务统计？ {#fu-31-12}&quot;">​</a></h5><p><strong>答</strong>：适合「近似实时计数」如当日调用次数监控、QPS 统计，不需精确余额；做配额扣减判定则不行，因 <code>sum()</code> 非原子读改。</p><h3 id="q-31-7" tabindex="-1">7. 高并发碳数据采集网关如何限流保护后端？ <a class="header-anchor" href="#q-31-7" aria-label="Permalink to &quot;7. 高并发碳数据采集网关如何限流保护后端？ {#q-31-7}&quot;">​</a></h3><p><strong>难度</strong>：★★</p><p><strong>考点</strong>：网关限流算法、令牌桶/漏桶、Sentinel 规则、碳数据上报峰值削峰。</p><p><strong>参考答案</strong>：在 API 网关（Spring Cloud Gateway）层用令牌桶算法限流，对单租户/单设备维度设 QPS 阈值；超限返回 429。结合 Sentinel 做热点参数限流（如某工厂设备突发刷数）。限流值应低于后端碳核算服务容量，作为第一道保护，避免海量 IoT 上报直接击穿数据库。</p><p><strong>深度解析</strong>：令牌桶允许短时突发（桶内积攒令牌），比漏桶更贴合 IoT 设备「定时批量上报」特征。Sentinel 支持 <code>flowRule</code> 按 QPS/线程数、链路、热点参数限流，并可降级（慢调用比例、异常比例）。网关层无状态易水平扩展，是限流首选位置。参考 Sentinel 1.8 流控文档。</p><p><strong>易错点</strong>：限流维度选错（只限全局不限租户）致大租户挤占小租户；阈值设死不随容量调整；限流后无降级兜底返回友好提示。</p><h4 id="f-31-7" tabindex="-1">追问： <a class="header-anchor" href="#f-31-7" aria-label="Permalink to &quot;追问： {#f-31-7}&quot;">​</a></h4><h5 id="fu-31-13" tabindex="-1">追问1：令牌桶和漏桶在碳上报场景差异？ <a class="header-anchor" href="#fu-31-13" aria-label="Permalink to &quot;追问1：令牌桶和漏桶在碳上报场景差异？ {#fu-31-13}&quot;">​</a></h5><p><strong>答</strong>：漏桶强制恒定速率，设备突发批量会被丢弃或排队；令牌桶允突发，契合设备整点集中上报。碳采集多选手桶，兼顾平滑与突发吸收。</p><h5 id="fu-31-14" tabindex="-1">追问2：限流后数据丢失怎么办？ <a class="header-anchor" href="#fu-31-14" aria-label="Permalink to &quot;追问2：限流后数据丢失怎么办？ {#fu-31-14}&quot;">​</a></h5><p><strong>答</strong>：网关限流仅拦「超额」请求，客户端应实现退避重试；核心数据走 MQ 异步入队，网关只接「提交成功」不保证处理，由 MQ 削峰保证不丢。</p><h3 id="q-31-8" tabindex="-1">8. 用 MQ 削峰填谷承接碳数据上报洪峰，如何保证不丢且有序？ <a class="header-anchor" href="#q-31-8" aria-label="Permalink to &quot;8. 用 MQ 削峰填谷承接碳数据上报洪峰，如何保证不丢且有序？ {#q-31-8}&quot;">​</a></h3><p><strong>难度</strong>：★★★</p><p><strong>考点</strong>：消息队列削峰、分区有序、幂等消费、碳数据最终一致、死信处理。</p><p><strong>参考答案</strong>：设备上报先发到 Kafka/RocketMQ，网关快速返回 202；消费者按 <code>tenantId+deviceId</code> 路由到固定分区保证同一设备顺序，后端批量落库。生产端开 <code>acks=all</code> + 本地消息表防丢，消费端用「处理前写去重表」幂等。洪峰时消息堆积由消费者集群横向扩容消费，实现削峰填谷。</p><p><strong>深度解析</strong>：Kafka 分区内有序，故用设备 ID 作 key 保序；RocketMQ 可借 <code>MessageGroup</code> 实现。可靠性靠「本地消息表 + 事务消息」或半同步复制。消费幂等用 <code>msgId</code> 或业务唯一键（如上报批次号）去重，避免重复落库导致碳数据翻倍。参考 RocketMQ 事务消息与 Kafka 精确一次语义（EOS）。</p><p><strong>易错点</strong>：无分区 key 导致同设备数据乱序、累计值错误；消费失败不进死信致阻塞；重复消费未去重使碳排量虚高。</p><h4 id="f-31-8" tabindex="-1">追问： <a class="header-anchor" href="#f-31-8" aria-label="Permalink to &quot;追问： {#f-31-8}&quot;">​</a></h4><h5 id="fu-31-15" tabindex="-1">追问1：消费跟不上堆积怎么处理？ <a class="header-anchor" href="#fu-31-15" aria-label="Permalink to &quot;追问1：消费跟不上堆积怎么处理？ {#fu-31-15}&quot;">​</a></h5><p><strong>答</strong>：监控 Lag，临时扩容消费者实例（Kafka 受分区数上限约束，需提前多分区）；或开启批量消费 + 异步刷库提升单实例吞吐，必要时降级非核心指标计算。</p><h5 id="fu-31-16" tabindex="-1">追问2：事务消息如何防止「库写成功但消息未发」？ <a class="header-anchor" href="#fu-31-16" aria-label="Permalink to &quot;追问2：事务消息如何防止「库写成功但消息未发」？ {#fu-31-16}&quot;">​</a></h5><p><strong>答</strong>：用 RocketMQ 事务消息：半消息→本地事务→Commit/Rollback；Broker 回查未知状态，本地据消息表状态决定提交，保证「数据库与消息」最终一致。</p><h3 id="q-31-9" tabindex="-1">9. 用舱壁隔离（Bulkhead）保护碳核算核心服务不被采集合并拖垮？ <a class="header-anchor" href="#q-31-9" aria-label="Permalink to &quot;9. 用舱壁隔离（Bulkhead）保护碳核算核心服务不被采集合并拖垮？ {#q-31-9}&quot;">​</a></h3><p><strong>难度</strong>：★★</p><p><strong>考点</strong>：舱壁模式、Resilience4j Bulkhead、线程池隔离、服务自我保护、碳核算稳定性。</p><p><strong>参考答案</strong>：碳核算（重 CPU/长耗时）与碳数据采集（高并发 I/O）共用线程池会互相影响。用 Resilience4j <code>Bulkhead</code> 对核算接口设独立信号量/线程池上限（如 20 并发），采集接口另设池。某接口被打满时只在自身舱内拒绝，不影响核算，实现故障隔离。</p><p><strong>深度解析</strong>：Bulkhead 两种：<code>SemaphoreBulkhead</code>（限并发数，轻量）与 <code>ThreadPoolBulkhead</code>（隔离线程池，适合阻塞调用）。核算属 CPU 密集用信号量防过载；采集 I/O 密集用线程池隔离防止连接占满。配合 <code>TimeLimiter</code> 防慢调用堆积。参考 Resilience4j 官方 Bulkhead 指南与 Netflix Hystrix 舱壁思想。</p><p><strong>易错点</strong>：所有接口共用默认池致采集洪峰占满线程、核算全超时；信号量舱壁未配超时仍可能堆积；隔离了线程却没隔离连接池。</p><h4 id="f-31-9" tabindex="-1">追问： <a class="header-anchor" href="#f-31-9" aria-label="Permalink to &quot;追问： {#f-31-9}&quot;">​</a></h4><h5 id="fu-31-17" tabindex="-1">追问1：Bulkhead 与限流（Sentinel）区别？ <a class="header-anchor" href="#fu-31-17" aria-label="Permalink to &quot;追问1：Bulkhead 与限流（Sentinel）区别？ {#fu-31-17}&quot;">​</a></h5><p><strong>答</strong>：限流按 QPS 控入口流量；Bulkhead 控并发占用资源数，防「慢请求堆积耗尽线程」。二者互补：网关限流挡峰值，舱壁保内部资源不被单类请求占满。</p><h5 id="fu-31-18" tabindex="-1">追问2：线程池舱壁如何设大小？ <a class="header-anchor" href="#fu-31-18" aria-label="Permalink to &quot;追问2：线程池舱壁如何设大小？ {#fu-31-18}&quot;">​</a></h5><p><strong>答</strong>：依任务类型与核数：CPU 密集≈核数，I/O 密集可放大（核数×期望并发因子）；结合压测确定，目标是满负载时拒绝新请求而非无限排队拖垮整体。</p><h3 id="q-31-10" tabindex="-1">10. 碳报告生成异步化：提交即返回任务ID，后台生成，如何通知用户？ <a class="header-anchor" href="#q-31-10" aria-label="Permalink to &quot;10. 碳报告生成异步化：提交即返回任务ID，后台生成，如何通知用户？ {#q-31-10}&quot;">​</a></h3><p><strong>难度</strong>：★★★</p><p><strong>考点</strong>：异步任务编排、任务状态表、SSE 实时推送、回调通知、碳报告长耗时处理。</p><p><strong>参考答案</strong>：前端提交生成请求，后端落 <code>report_task</code>（status=PROCESSING）并返 <code>taskId</code>，立刻响应。后台线程/Worker 计算（含因子检索、LCA 模型），进度写任务表。通知二选一：SSE 长连接由前端订阅 <code>/report/{taskId}/stream</code> 实时收进度；或完成后 Webhook 回调业务系统。用户也可轮询任务状态。</p><p><strong>深度解析</strong>：SSE（Server-Sent Events）基于 HTTP 单向流，适合「服务端推进度」，比 WebSocket 轻、自带断线重连。后端用 <code>SseEmitter</code>（Spring）保持连接，进度变更 <code>send()</code>。任务表需含 <code>status/progress/result_url/error</code>，保证可查询与幂等重入。报告生成失败写 <code>FAILED</code> 并保留原因供排查。</p><p><strong>易错点</strong>：任务表无状态机致重复生成；SSE 连接未设超时致连接泄漏；回调地址未鉴权被伪造；前端未处理断线重连丢进度。</p><h4 id="f-31-10" tabindex="-1">追问： <a class="header-anchor" href="#f-31-10" aria-label="Permalink to &quot;追问： {#f-31-10}&quot;">​</a></h4><h5 id="fu-31-19" tabindex="-1">追问1：SSE 与 WebSocket 怎么选？ <a class="header-anchor" href="#fu-31-19" aria-label="Permalink to &quot;追问1：SSE 与 WebSocket 怎么选？ {#fu-31-19}&quot;">​</a></h5><p><strong>答</strong>：仅服务端单向推进度/结果用 SSE 更简单、自动重连；需双向交互（如用户中途改参数）才用 WebSocket。碳报告进度推 SSE 足够，省去全双工复杂度。</p><h5 id="fu-31-20" tabindex="-1">追问2：任务重复提交如何防？ <a class="header-anchor" href="#fu-31-20" aria-label="Permalink to &quot;追问2：任务重复提交如何防？ {#fu-31-20}&quot;">​</a></h5><p><strong>答</strong>：以「租户+报告类型+参数哈希」做幂等键，提交前查无进行中任务则创建，否则返已有 taskId；Worker 取任务前用数据库行锁/Redis 标记防多实例重复执行。</p><h3 id="q-31-11" tabindex="-1">11. 多租户碳数据如何用分表/分库做隔离？ <a class="header-anchor" href="#q-31-11" aria-label="Permalink to &quot;11. 多租户碳数据如何用分表/分库做隔离？ {#q-31-11}&quot;">​</a></h3><p><strong>难度</strong>：★★★</p><p><strong>考点</strong>：多租户隔离策略、ShardingSphere 分片、租户路由、数据安全边界、碳数据合规。</p><p><strong>参考答案</strong>：SaaS 碳管家按租户隔离：采用「共享库分表」——以 <code>tenant_id</code> 为分片键，用 ShardingSphere 把 <code>carbon_emission</code> 拆为 <code>carbon_emission_${tenant_id % 64}</code>。路由在 JDBC 层自动拼分片，SQL 无需改动。超大型租户可独立物理库（独立 datasource）。所有查询强制带 <code>tenant_id</code> 避免越权跨租户读。</p><p><strong>深度解析</strong>：隔离三档——字段隔离（同表加 tenant_id，最省但易串）、分表/分库（隔离好、运维复杂）、独立部署（最强）。碳数据涉商业机密，常用分表+行级 <code>tenant_id</code> 双保险。ShardingSphere 的 <code>Hint</code> 或 <code>ShardingAlgorithm</code> 实现路由；注意跨租户聚合统计需单独汇总库。参考 ShardingSphere 5.x 多租户文档。</p><p><strong>易错点</strong>：分片键选错（用 user_id 而非 tenant_id）致同租户数据散落；忘记强制 tenant_id 过滤致越权；跨分片 <code>JOIN</code>/<code>count</code> 性能崩。</p><h4 id="f-31-11" tabindex="-1">追问： <a class="header-anchor" href="#f-31-11" aria-label="Permalink to &quot;追问： {#f-31-11}&quot;">​</a></h4><h5 id="fu-31-21" tabindex="-1">追问1：分表后如何做跨租户统计？ <a class="header-anchor" href="#fu-31-21" aria-label="Permalink to &quot;追问1：分表后如何做跨租户统计？ {#fu-31-21}&quot;">​</a></h5><p><strong>答</strong>：建独立 OLAP 汇总库（如通过 CDC 同步到 StarRocks/ClickHouse），专跑跨租户聚合，避免在生产分表上跑重查询影响在线事务。</p><h5 id="fu-31-22" tabindex="-1">追问2：分表数量如何定？ <a class="header-anchor" href="#fu-31-22" aria-label="Permalink to &quot;追问2：分表数量如何定？ {#fu-31-22}&quot;">​</a></h5><p><strong>答</strong>：按数据量与单表上限（建议≤500万行）估算，留 2–3 倍余量；过多分片增连接与元数据开销，建议 2 的幂（64/128）便于取模与后期再分。</p><h3 id="q-31-12" tabindex="-1">12. Milvus collection 与 Redis key 前缀如何实现多租户碳向量隔离？ <a class="header-anchor" href="#q-31-12" aria-label="Permalink to &quot;12. Milvus collection 与 Redis key 前缀如何实现多租户碳向量隔离？ {#q-31-12}&quot;">​</a></h3><p><strong>难度</strong>：★★</p><p><strong>考点</strong>：向量库多租户、Milvus partition/collection、Redis key 命名空间、向量检索隔离、碳因子租户边界。</p><p><strong>参考答案</strong>：Milvus 中每个租户的碳因子向量可用独立 collection（强隔离）或同一 collection 下按 <code>tenant_id</code> 建 partition（轻量）。检索时用 <code>partition_names</code> 限定，避免跨租户召回。Redis 碳配额/缓存 Key 统一加 <code>tenant:{tenantId}:</code> 前缀，清除与统计按前缀批量操作，杜绝串租户。</p><p><strong>深度解析</strong>：collection 隔离资源独占、权限清晰但数量受管控上限；partition 共享 schema、按租户过滤灵活，适合租户多且单租户数据量中等的 LCA 场景。Milvus 2.x 支持 <code>partition_key</code> 自动路由。Redis 前缀法简单，配合 <code>SCAN tenant:{id}:*</code> 做租户级清理。二者都依赖「写入即带租户标识」的纪律。</p><p><strong>易错点</strong>：向量检索忘传 partition 致跨租户召回泄露因子；Redis 前缀拼错（漏分隔符）致 Key 冲突；清缓存用 <code>KEYS *</code> 阻塞生产。</p><h4 id="f-31-12" tabindex="-1">追问： <a class="header-anchor" href="#f-31-12" aria-label="Permalink to &quot;追问： {#f-31-12}&quot;">​</a></h4><h5 id="fu-31-23" tabindex="-1">追问1：租户极多时 collection 爆炸怎么办？ <a class="header-anchor" href="#fu-31-23" aria-label="Permalink to &quot;追问1：租户极多时 collection 爆炸怎么办？ {#fu-31-23}&quot;">​</a></h5><p><strong>答</strong>：改 partition 或字段过滤（在向量库元数据加 tenant_id，检索加 filter_expr），避免每租户一 collection；Milvus 用 <code>partition_key</code> 自动分片，兼顾隔离与规模。</p><h5 id="fu-31-24" tabindex="-1">追问2：Redis 批量删租户数据为什么不用 KEYS？ <a class="header-anchor" href="#fu-31-24" aria-label="Permalink to &quot;追问2：Redis 批量删租户数据为什么不用 KEYS？ {#fu-31-24}&quot;">​</a></h5><p><strong>答</strong>：<code>KEYS</code> 全量遍历阻塞单线程实例，生产禁用；应 <code>SCAN</code> 游标分批删，或用 Redis 7 <code>UNLINK</code> 异步删，或把租户数据放独立 DB 编号整库清。</p><h3 id="q-31-13" tabindex="-1">13. 分布式事务边界：碳核算为什么不能重复计算，如何用幂等标记 idempotent=false 排除重试？ <a class="header-anchor" href="#q-31-13" aria-label="Permalink to &quot;13. 分布式事务边界：碳核算为什么不能重复计算，如何用幂等标记 idempotent=false 排除重试？ {#q-31-13}&quot;">​</a></h3><p><strong>难度</strong>：★★★</p><p><strong>考点</strong>：幂等设计、MQ 重试、分布式事务边界、重复计算风险、碳核算准确性。</p><p><strong>参考答案</strong>：碳核算若因网络重试、消息重投被重复执行，同一笔排放会被多次计入，总碳量虚高，违背「不重复计算」原则。方案：每条核算任务带全局唯一 <code>bizKey</code>（如 <code>tenant+sourceId+period</code>），处理前查「已核算表」；消息消费侧对可安全重试的幂等操作标记 <code>idempotent=false</code>（即该步骤非天然幂等，须显式去重），其余天然幂等操作才允许重试。</p><p><strong>深度解析</strong>：在可靠消息/重试框架中，<code>idempotent=false</code> 表示「此动作重复执行有副作用，需框架或业务拦截重复」。碳核算属非幂等写，必须落「核算流水」以 <code>bizKey</code> 唯一约束挡重；而「查因子」等读操作可标 <code>idempotent=true</code> 放心重试。Seata/TCC 的 Cancel 也依赖幂等。参考分布式事务「幂等七字诀：唯一键+状态机」。</p><p><strong>易错点</strong>：把可重试接口的 <code>idempotent</code> 误标导致重复扣减；只靠上游「保证不重发」不可靠；bizKey 设计缺时间维度致历史期被覆盖。</p><h4 id="f-31-13" tabindex="-1">追问： <a class="header-anchor" href="#f-31-13" aria-label="Permalink to &quot;追问： {#f-31-13}&quot;">​</a></h4><h5 id="fu-31-25" tabindex="-1">追问1：idempotent=false 在框架里具体怎么用？ <a class="header-anchor" href="#fu-31-25" aria-label="Permalink to &quot;追问1：idempotent=false 在框架里具体怎么用？ {#fu-31-25}&quot;">​</a></h5><p><strong>答</strong>：在重试组件（如 Spring Retry/自研）对标注 <code>@Retryable(idempotent=false)</code> 的方法，执行前先占分布式锁/去重表，失败回滚标记，成功写完成；重复调用直接命中已完成记录短路返回，避免副作用。</p><h5 id="fu-31-26" tabindex="-1">追问2：bizKey 如何设计才兼顾防重与可追溯？ <a class="header-anchor" href="#fu-31-26" aria-label="Permalink to &quot;追问2：bizKey 如何设计才兼顾防重与可追溯？ {#fu-31-26}&quot;">​</a></h5><p><strong>答</strong>：用 <code>tenantId:dataSource:entityId:period</code> 拼接，唯一索引防重；同时保留 <code>requestId</code> 便于按原始请求追溯，核算流水表存 <code>bizKey+requestId+status</code> 形成审计链。</p><h3 id="q-31-14" tabindex="-1">14. 用 CompletableFuture 编排碳足迹多源聚合（因子库+活动数据+历史基线）提升吞吐？ <a class="header-anchor" href="#q-31-14" aria-label="Permalink to &quot;14. 用 CompletableFuture 编排碳足迹多源聚合（因子库+活动数据+历史基线）提升吞吐？ {#q-31-14}&quot;">​</a></h3><p><strong>难度</strong>：★★</p><p><strong>考点</strong>：CompletableFuture 组合、自定义线程池、异常恢复、多源并发聚合、碳足迹计算编排。</p><p><strong>参考答案</strong>：碳足迹需并行取「排放因子（Milvus/MySQL）」「活动数据（设备上报库）」「历史基线（OLAP）」三类数据。用 <code>CompletableFuture.supplyAsync(..., bizExecutor)</code> 并发拉取，再用 <code>thenCombine</code>/<code>allOf</code> 汇聚，总耗时≈最慢源而非三者之和。任一源失败用 <code>exceptionally</code> 给兜底（如缺因子用默认值并标脏数据）。</p><p><strong>深度解析</strong>：务必传自定义 <code>Executor</code>，否则默认 <code>ForkJoinPool.commonPool()</code> 被全局共享、且虚拟线程下语义不同。I/O 密集源可配虚拟线程执行器提速。汇聚后做单位换算与 GWP 加权。注意 <code>allOf</code> 不返回值，需内部收集；<code>thenApply</code> 链别吞异常。参考 <code>CompletableFuture</code> API 与「上下文传递」陷阱（MDC 丢失）。</p><p><strong>易错点</strong>：用 commonPool 致业务线程与系统任务争抢；异常被 <code>handle</code> 吞掉无告警；并行度过高打爆下游因子库（需配合 Semaphore）。</p><h4 id="f-31-14" tabindex="-1">追问： <a class="header-anchor" href="#f-31-14" aria-label="Permalink to &quot;追问： {#f-31-14}&quot;">​</a></h4><h5 id="fu-31-27" tabindex="-1">追问1：CompletableFuture 与虚拟线程怎么结合？ <a class="header-anchor" href="#fu-31-27" aria-label="Permalink to &quot;追问1：CompletableFuture 与虚拟线程怎么结合？ {#fu-31-27}&quot;">​</a></h5><p><strong>答</strong>：把 <code>supplyAsync</code> 的执行器换成 <code>Executors.newVirtualThreadPerTaskExecutor()</code>，每个源一个虚拟线程，I/O 等待不占平台线程；组合逻辑不变，编排更轻，避免线程池容量焦虑。</p><h5 id="fu-31-28" tabindex="-1">追问2：如何保证多源结果可追溯？ <a class="header-anchor" href="#fu-31-28" aria-label="Permalink to &quot;追问2：如何保证多源结果可追溯？ {#fu-31-28}&quot;">​</a></h5><p><strong>答</strong>：每源结果包 <code>(data, source, fetchTs, status)</code>，汇聚后生成 lineage 记录，标明哪些因子来自默认值；报告可展示「数据可信度」，便于碳管家 AI 助手提示用户补全。</p><h3 id="q-31-15" tabindex="-1">15. 碳因子数据通过 CDC 从 MySQL 同步到 ES/Milvus，如何保障一致与对账？ <a class="header-anchor" href="#q-31-15" aria-label="Permalink to &quot;15. 碳因子数据通过 CDC 从 MySQL 同步到 ES/Milvus，如何保障一致与对账？ {#q-31-15}&quot;">​</a></h3><p><strong>难度</strong>：★★★</p><p><strong>考点</strong>：CDC（Change Data Capture）、Flink/Debezium、最终一致、对账、碳因子版本漂移。</p><p><strong>参考答案</strong>：用 Flink CDC 监听 MySQL <code>carbon_factor</code> 的 binlog，实时写入 ES（文本检索）与 Milvus（向量）。每条因子带 <code>version</code> 与 <code>updated_at</code>。下游消费时校验版本顺序（单调递增），乱序丢弃旧版。每日跑对账 Job：比 MySQL 与 ES/Milvus 的因子数、版本号、关键字段哈希，差异告警并重推。</p><p><strong>深度解析</strong>：CDC 避免「双写」不一致，以 DB 为唯一源。Flink 可做 transform（如文本向量化在算子内调用 Embedding）。需处理 delete（ES 删文档、Milvus 删向量）、schema 变更。最终一致窗口内查到旧因子，业务层可按 <code>updated_at</code> 容忍。参考 Flink CDC 3.x 与 Debezium 文档。</p><p><strong>易错点</strong>：向量化在 CDC 链路超时阻塞整条流；删操作漏同步致脏因子残留；对账只看条数不看内容，字段漂移发现不了。</p><h4 id="f-31-15" tabindex="-1">追问： <a class="header-anchor" href="#f-31-15" aria-label="Permalink to &quot;追问： {#f-31-15}&quot;">​</a></h4><h5 id="fu-31-29" tabindex="-1">追问1：CDC 链路故障积压如何止血？ <a class="header-anchor" href="#fu-31-29" aria-label="Permalink to &quot;追问1：CDC 链路故障积压如何止血？ {#fu-31-29}&quot;">​</a></h5><p><strong>答</strong>：Flink 开启 checkpoint 与 exactly-once，故障从位点重放；积压时临时提并行度； Embedding 调用慢则降级为异步旁路向量化，主链路只同步结构化字段，保核心可用。</p><h5 id="fu-31-30" tabindex="-1">追问2：向量库和关系库版本不一致会算错吗？ <a class="header-anchor" href="#fu-31-30" aria-label="Permalink to &quot;追问2：向量库和关系库版本不一致会算错吗？ {#fu-31-30}&quot;">​</a></h5><p><strong>答</strong>：会，可能用旧 GWP 因子致排放偏差。故对账必查 <code>version</code>，且报告生成时优先取 MySQL 权威因子、向量库仅用于「相似推荐」，关键计算不走近似源。</p><h3 id="q-31-16" tabindex="-1">16. 碳管家 AI 助手实时推送核算进度，SSE 断线重连与背压怎么处理？ <a class="header-anchor" href="#q-31-16" aria-label="Permalink to &quot;16. 碳管家 AI 助手实时推送核算进度，SSE 断线重连与背压怎么处理？ {#q-31-16}&quot;">​</a></h3><p><strong>难度</strong>：★★</p><p><strong>考点</strong>：SSE 生命周期、Spring SseEmitter、超时/重连、背压、AI 流式回答。</p><p><strong>参考答案</strong>：AI 助手边算边推（含 LLM 流式 token 与核算进度），用 <code>SseEmitter</code> 维持连接，设 <code>timeout</code> 并注册 <code>onCompletion/onError</code> 清理。客户端断线后带 <code>Last-Event-ID</code> 重连，服务端据 <code>taskId+offset</code> 续推。背压方面：若推送快于消费，<code>SseEmitter.send</code> 抛 <code>IllegalStateException</code> 时标记客户端慢、降级为摘要推送或转轮询。</p><p><strong>深度解析</strong>：SSE 默认文本流、<code>retry:</code> 字段控制重连间隔。Spring 中每个 <code>SseEmitter</code> 占一个连接，需池化/超时回收防泄漏。AI 流式输出可 <code>map</code> 成 SSE 事件；核算进度独立事件类型。背压本质是客户端消费能力，服务端不能无限缓存，应限缓冲队列长度。参考 HTML5 SSE 规范与 Spring WebMVC SseEmitter。</p><p><strong>易错点</strong>：Emitter 不关致内存泄漏；重连不带偏移致进度重复推；未处理客户端慢致服务端 OOM。</p><h4 id="f-31-16" tabindex="-1">追问： <a class="header-anchor" href="#f-31-16" aria-label="Permalink to &quot;追问： {#f-31-16}&quot;">​</a></h4><h5 id="fu-31-31" tabindex="-1">追问1：SSE 能推二进制向量吗？ <a class="header-anchor" href="#fu-31-31" aria-label="Permalink to &quot;追问1：SSE 能推二进制向量吗？ {#fu-31-31}&quot;">​</a></h5><p><strong>答</strong>：SSE 仅文本，向量需 base64 或 JSON 编码为字符串事件；大向量建议只推「完成+结果 URL」，前端再拉取，避免 SSE 帧过大阻塞。</p><h5 id="fu-31-32" tabindex="-1">追问2：多实例部署 SSE 如何找到对的连接？ <a class="header-anchor" href="#fu-31-32" aria-label="Permalink to &quot;追问2：多实例部署 SSE 如何找到对的连接？ {#fu-31-32}&quot;">​</a></h5><p><strong>答</strong>：用发布订阅（Redis Pub/Sub 或 MQ）：进度事件发到 <code>report:{taskId}</code> 频道，持有该 SseEmitter 的实例消费并推送；无对应连接则丢弃或转持久化待重连拉取。</p><h3 id="q-31-17" tabindex="-1">17. 积木LCA云中「报告生成 + 配额扣减」如何用 TCC 避免配额超发与报告孤儿？ <a class="header-anchor" href="#q-31-17" aria-label="Permalink to &quot;17. 积木LCA云中「报告生成 + 配额扣减」如何用 TCC 避免配额超发与报告孤儿？ {#q-31-17}&quot;">​</a></h3><p><strong>难度</strong>：★★★</p><p><strong>考点</strong>：TCC 业务落地、配额预留、报告任务与配额绑定、异常补偿、LCA 报告一致性。</p><p><strong>参考答案</strong>：Try：为报告预留 AI 配额（冻结 N 单位），创建 <code>report_task</code>（status=RESERVED）。Confirm：报告生成成功，真实扣减冻结配额、置 <code>status=DONE</code>。Cancel：生成失败/超时，释放冻结配额、置 <code>status=CANCELLED</code>。配额与任务通过 <code>taskId</code> 绑定，Confirm/Cancel 幂等，确保「有报告必有扣减、扣了必有报告」二选一，杜绝超发与孤儿报告。</p><p><strong>深度解析</strong>：LCA 报告含大量因子计算与 LLM 调用，耗配额且慢，必须「先预留后使用」。TCC 的冻结量即「最大可能消耗」，Confirm 按实际结算（多退少补）。超时被全局事务定时器触发 Cancel 释放，防配额被永久钉死。参考 Seata TCC 与「配额即资源」建模。</p><p><strong>易错点</strong>：Try 不冻结致并发超发；Confirm 按预估而非实际扣减致账目偏差；超时未触发 Cancel 致配额泄漏。</p><h4 id="f-31-17" tabindex="-1">追问： <a class="header-anchor" href="#f-31-17" aria-label="Permalink to &quot;追问： {#f-31-17}&quot;">​</a></h4><h5 id="fu-31-33" tabindex="-1">追问1：Confirm 实际消耗与冻结不一致怎么办？ <a class="header-anchor" href="#fu-31-33" aria-label="Permalink to &quot;追问1：Confirm 实际消耗与冻结不一致怎么办？ {#fu-31-33}&quot;">​</a></h5><p><strong>答</strong>：Try 冻结「上限」，Confirm 用 <code>实际消耗</code> 更新余额并释放余量（<code>balance -= actual; frozen -= actual</code>）；若 actual&gt;frozen 属异常需告警人工，正常业务应保证 actual≤frozen。</p><h5 id="fu-31-34" tabindex="-1">追问2：报告生成极慢，冻结长期占用的对策？ <a class="header-anchor" href="#fu-31-34" aria-label="Permalink to &quot;追问2：报告生成极慢，冻结长期占用的对策？ {#fu-31-34}&quot;">​</a></h5><p><strong>答</strong>：设配额冻结 TTL，超时自动 Cancel 释放并标记任务失败，用户可重提；或对长任务改用「按阶段小步扣减」而非一次性大冻结，降低占用周期。</p><h3 id="q-31-18" tabindex="-1">18. 碳数据采集高并发下，如何用 Semaphore + 虚拟线程做下游写入限流与背压？ <a class="header-anchor" href="#q-31-18" aria-label="Permalink to &quot;18. 碳数据采集高并发下，如何用 Semaphore + 虚拟线程做下游写入限流与背压？ {#q-31-18}&quot;">​</a></h3><p><strong>难度</strong>：★★</p><p><strong>考点</strong>：虚拟线程背压、Semaphore 限流、下游保护、批量写入、采集链路稳定性。</p><p><strong>参考答案</strong>：采集入口接大量设备上报，下游是 MySQL/时序库写入（瓶颈）。用虚拟线程接收（I/O 不占平台线程），但在写库前用 <code>Semaphore(dbPermits)</code> 限并发写数（如 50），超出则虚拟线程挂起等待，形成软背压，避免瞬时万级写入压垮 DB。到达许可的虚拟线程批量攒批（<code>batchInsert</code>）提升吞吐。</p><p><strong>深度解析</strong>：虚拟线程让「每请求一线程」成本极低，但下游 DB 连接/写入能力有限，必须由 Semaphore 做准入。背压本质是把「下游处理不了的压力」转化为「上游虚拟线程阻塞」而非无限堆积队列。批量写降低单条事务开销。配合连接池（HikariCP）<code>maximumPoolSize</code> 双重限流。</p><p><strong>易错点</strong>：只开虚拟线程不限下游，DB 连接耗尽全链路超时；Semaphore 与连接池上限不一致致死锁式阻塞；批量攒批无上限致内存涨。</p><h4 id="f-31-18" tabindex="-1">追问： <a class="header-anchor" href="#f-31-18" aria-label="Permalink to &quot;追问： {#f-31-18}&quot;">​</a></h4><h5 id="fu-31-35" tabindex="-1">追问1：Semaphore 和连接池最大连接数如何配？ <a class="header-anchor" href="#fu-31-35" aria-label="Permalink to &quot;追问1：Semaphore 和连接池最大连接数如何配？ {#fu-31-35}&quot;">​</a></h5><p><strong>答</strong>：令 <code>Semaphore permits ≈ HikariCP maximumPoolSize</code>（略小），保证「拿到许可必能取连接」，避免许可到手却等连接；二者同向收敛到 DB 真实承受能力。</p><h5 id="fu-31-36" tabindex="-1">追问2：虚拟线程阻塞在 Semaphore 会钉住载体吗？ <a class="header-anchor" href="#fu-31-36" aria-label="Permalink to &quot;追问2：虚拟线程阻塞在 Semaphore 会钉住载体吗？ {#fu-31-36}&quot;">​</a></h5><p><strong>答</strong>：不会。<code>Semaphore.acquire()</code> 是纯 Java 锁等待，虚拟线程会卸载（unmount）让出 carrier thread，载体可调度其他虚拟线程，这正是虚拟线程相比平台线程的优势。</p>',199)])])}const g=o(n,[["render",d]]);export{p as __pageData,g as default};
